; 愚者の倉庫

name = 愚者の倉庫６
insideName = Floor 6
level = 23
bgm = trick
external = s:1
shadow = dark
sky = black
roof = stone
blank = rock
antiWarp = true

; 各パーツ
━ = stone
　 = marble
❖ = marble
☆ = soilr
❑ = cube
⧻ = fence
☖ = arch
☗ = gate
︻ = panel

; 移動ポイント
(A) = map:愚者の倉庫５, x:10, y:10, way:w, symbol:exit, ask:Go to the previous floor?
(B) = map:愚者の倉庫７, x:5, y:13, way:s, symbol:exit, ask:Go to the next floor?

; 宝箱
box[1] = 罠はない,鏡の盾_u,オリハルコンの砂,経験のコイン（中）

